#nullable enable // autogenerated

using MVZ2.GameContent.Detections;
using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Projectiles;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Entities;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    public abstract class CatapultBehaviour : AIEntityBehaviour
    {
        public CatapultBehaviour(string nsp, string name) : base(nsp, name)
        {
            detector = GetDetector();
        }

        public void CatapultUpdate(Entity entity)
        {
            var state = GetCatapultState(entity);
            switch (state)
            {
                case CATAPULT_STATE_IDLE:
                    IdleUpdate(entity);
                    break;
                case CATAPULT_STATE_ATTACK:
                    AttackUpdate(entity);
                    break;
                case CATAPULT_STATE_THROWN:
                    ThrownUpdate(entity);
                    break;
            }
        }
        public void UpdateAnimation(Entity entity)
        {
            entity.SetAnimationInt("ThrowState", GetAnimationThrowState(entity));
            entity.SetAnimationFloat("AttackSpeed", entity.IsAIFrozen() ? 0 : entity.GetAttackSpeed());
        }
        public void IdleUpdate(Entity entity)
        {
            var timer = GetStateTimer(entity);
            if (timer == null)
            {
                timer = new FrameTimer(GetAttackInterval(entity));
                SetStateTimer(entity, timer);
            }
            if (timer.RunToExpired(entity.GetAttackSpeed()))
            {
                var target = detector.DetectEntityWithTheLeast(entity, e => GetTargetPriority(e, entity));
                if (target != null)
                {
                    SetCatapultState(entity, CATAPULT_STATE_ATTACK);
                    SetThrowTarget(entity, new EntityID(target));
                    timer.ResetTime(GetThrowTime(entity));
                    OnIdleTimeout(entity);
                }
                else
                {
                    timer.ResetTime(GetAttackInterval(entity));
                }
            }
        }
        public void AttackUpdate(Entity entity)
        {
            var timer = GetStateTimer(entity);
            if (timer == null)
            {
                timer = new FrameTimer(GetThrowTime(entity));
                SetStateTimer(entity, timer);
            }
            if (timer.RunToExpired(entity.GetAttackSpeed()))
            {
                SetCatapultState(entity, CATAPULT_STATE_THROWN);
                timer.ResetTime(GetRestoreTime(entity));
                OnAttackTimeout(entity);
            }
        }
        public void ThrownUpdate(Entity entity)
        {
            var timer = GetStateTimer(entity);
            if (timer == null)
            {
                timer = new FrameTimer(GetRestoreTime(entity));
                SetStateTimer(entity, timer);
            }
            if (timer.RunToExpired(entity.GetAttackSpeed()))
            {
                SetCatapultState(entity, CATAPULT_STATE_IDLE);
                timer.ResetTime(GetAttackInterval(entity));
                OnThrownTimeout(entity);
            }
        }
        public virtual void OnIdleTimeout(Entity entity)
        {
        }
        public virtual void OnAttackTimeout(Entity entity)
        {
            ThrowProjectile(entity);
        }
        public virtual void OnThrownTimeout(Entity entity)
        {
        }
        public virtual Entity? ThrowProjectile(Entity entity)
        {
            var param = entity.GetShootParams();
            PreModifyShootParameters(entity, ref param);
            var throwTargetID = GetThrowTarget(entity);
            var throwTarget = throwTargetID?.GetEntity(entity.Level);
            var flyTime = Ticks.FromSeconds(PROJECTILE_FLY_TIME_SECONDS);
            Vector3 targetPosition;
            if (throwTarget != null && throwTarget.ExistsAndAlive())
            {
                var bounds = throwTarget.GetBounds();
                targetPosition = bounds.center;
                targetPosition.y = bounds.max.y;
                targetPosition += throwTarget.Velocity * flyTime;

                GetLimitTargetPositionX(entity, out var minX, out var maxX);
                GetLimitTargetPositionZ(entity, out var minZ, out var maxZ);
                targetPosition.x = Mathf.Clamp(targetPosition.x, minX, maxX);
                targetPosition.z = Mathf.Clamp(targetPosition.z, minZ, maxZ);
            }
            else
            {
                var level = entity.Level;
                var lane = entity.GetLane();
                var x = level.GetEntityColumnX(level.GetMaxColumnCount() - 1);
                var z = level.GetEntityLaneZ(lane);
                var y = level.GetGroundY(x, z);
                targetPosition = new Vector3(x, y, z);
            }
            var projectileId = param.projectileID;
            var projectileDefinition = entity.Level.Content.GetEntityDefinition(projectileId);
            var gravity = projectileDefinition?.GetGravity() ?? 1;
            param.velocity = VanillaProjectileExt.GetLobVelocityByTime(param.position, targetPosition, flyTime, gravity);
            PostModifyShootParameters(entity, ref param);
            return entity.ShootProjectile(param);
        }
        public virtual float GetTargetPriority(Entity target, Entity entity)
        {
            float priority = 0;
            if (entity.IsFacingLeft())
            {
                priority += entity.GetCenter().x - target.GetCenter().x;
            }
            else
            {
                priority += target.GetCenter().x - entity.GetCenter().x;
            }
            if (target.Type == EntityTypes.OBSTACLE)
            {
                priority += 100000;
            }
            return priority;
        }
        public virtual void GetLimitTargetPositionX(Entity entity, out float min, out float max)
        {
            if (entity.IsFacingLeft())
            {
                min = entity.Position.x - entity.GetRange();
                max = entity.Position.x;
            }
            else
            {
                min = entity.Position.x;
                max = entity.Position.x + entity.GetRange();
            }
        }
        public virtual void GetLimitTargetPositionZ(Entity entity, out float min, out float max)
        {
            min = entity.Position.z - 20;
            max = entity.Position.z + 20;
        }
        protected virtual void PreModifyShootParameters(Entity entity, ref ShootParams param)
        {

        }
        protected virtual void PostModifyShootParameters(Entity entity, ref ShootParams param)
        {

        }
        protected virtual int GetAnimationThrowState(Entity entity)
        {
            var state = GetCatapultState(entity);
            switch (state)
            {
                case CATAPULT_STATE_ATTACK:
                case CATAPULT_STATE_THROWN:
                    return ANIMATION_THROW_STATE_ATTACK;
                default:
                    return ANIMATION_THROW_STATE_IDLE;
            }
        }
        protected virtual int GetAttackInterval(Entity entity)
        {
            int frames = AttackIntervalMax;
            if (!entity.Level.IsIZombie())
            {
                frames = entity.RNG.Next(AttackIntervalMin, AttackIntervalMax);
            }
            return frames;
        }
        protected virtual int GetThrowTime(Entity entity)
        {
            return Ticks.FromSeconds(0.25f);
        }
        protected virtual int GetRestoreTime(Entity entity)
        {
            return Ticks.FromSeconds(0.75f);
        }
        protected virtual Detector GetDetector()
        {
            return new CatapultDetector();
        }
        public static int GetCatapultState(Entity entity) => entity.GetProperty<int>(PROP_CATAPULT_STATE);
        public static void SetCatapultState(Entity entity, int value) => entity.SetProperty(PROP_CATAPULT_STATE, value);
        public static FrameTimer? GetStateTimer(Entity entity) => entity.GetProperty<FrameTimer>(PROP_STATE_TIMER);
        public static void SetStateTimer(Entity entity, FrameTimer? value) => entity.SetProperty(PROP_STATE_TIMER, value);
        public static EntityID? GetThrowTarget(Entity entity) => entity.GetProperty<EntityID>(PROP_THROW_TARGET);
        public static void SetThrowTarget(Entity entity, EntityID? value) => entity.SetProperty(PROP_THROW_TARGET, value);
        public virtual int AttackIntervalMin { get; } = Ticks.FromSeconds(1.666667f);
        public virtual int AttackIntervalMax { get; } = Ticks.FromSeconds(2f);
        public const int CATAPULT_STATE_IDLE = 0;
        public const int CATAPULT_STATE_ATTACK = 1;
        public const int CATAPULT_STATE_THROWN = 2;
        public const int ANIMATION_THROW_STATE_IDLE = 0;
        public const int ANIMATION_THROW_STATE_ATTACK = 1;
        public const float PROJECTILE_FLY_TIME_SECONDS = 1f;
        protected Detector detector;
        private const string PROP_REGION = "catapult";
        [EntityPropertyRegistry(PROP_REGION)]
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_STATE_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("state_timer");
        [EntityPropertyRegistry(PROP_REGION)]
        public static readonly VanillaEntityPropertyMeta<int> PROP_CATAPULT_STATE = new VanillaEntityPropertyMeta<int>("catapult_state");
        [EntityPropertyRegistry(PROP_REGION)]
        public static readonly VanillaEntityPropertyMeta<EntityID> PROP_THROW_TARGET = new VanillaEntityPropertyMeta<EntityID>("throw_target");
    }
}